SELECT *
FROM c_code



        AND category = #{condition.category}




        AND code = #{code}




        AND `describe` = #{condition.describe}




        AND (
        category LIKE CONCAT('%', #{condition.key}, '%')
        OR code LIKE CONCAT('%', #{condition.key}, '%')
        OR `describe` LIKE CONCAT('%', #{condition.key}, '%')
        )



order by update_time desc
